queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?format_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFormats ?child ; p:hasBroadcasts ?parent . } GROUP BY ?child }
  ?child p:format_name ?format_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Broadcasts } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?format_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFormats ?child ; p:hasBroadcasts ?parent . } GROUP BY ?child }
  ?child p:format_name ?format_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Broadcasts } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?title ?format_name WHERE {
  ?broadcasts_formats a :Broadcasts_Formats .
  ?formats a :Formats .
  ?broadcasts_formats p:hasFormats ?formats .
  ?broadcasts a :Broadcasts .
  ?broadcasts_formats p:hasBroadcasts ?broadcasts .
  ?broadcasts p:title ?title .
  ?formats p:format_name ?format_name .
} }
}
